const TRUSTED_SOURCES = ['fastcompany.com','hbr.org','woccu.org','bcorporation.net','forbes.com','adweek.com'];
const COOP_KEYWORDS = ['b corp','esg','purpose','cooperative','credit union','stakeholder capitalism'];

const news = $input.all()[0].json.news || [];
const scored = [];

for (const item of news) {
  let score = 0.5;
  const url = (item.link || '').toLowerCase();
  const combined = ((item.title || '') + ' ' + (item.snippet || '')).toLowerCase();

  if (TRUSTED_SOURCES.some(s => url.includes(s))) score += 0.3;
  const kwMatches = COOP_KEYWORDS.filter(kw => combined.includes(kw)).length;
  score += Math.min(kwMatches * 0.1, 0.20);

  score = Math.min(Math.max(parseFloat(score.toFixed(2)), 0), 1);
  if (score >= 0.70) {
    scored.push({ json: { title: item.title, link: item.link, snippet: item.snippet, source: item.source, date: item.date, source_score: score, vertical: 'geral' } });
  }
}
scored.sort((a, b) => b.json.source_score - a.json.source_score);
return scored.slice(0, 3);

